CREATE DATABASE IF NOT EXISTS ai_internship_management CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE ai_internship_management;

CREATE TABLE admins (id CHAR(36) PRIMARY KEY, name VARCHAR(120) NOT NULL, email VARCHAR(160) NOT NULL UNIQUE, phone VARCHAR(30), department VARCHAR(120), password_hash VARCHAR(255) NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE mentors (id CHAR(36) PRIMARY KEY, name VARCHAR(120) NOT NULL, email VARCHAR(160) NOT NULL UNIQUE, phone VARCHAR(30), department VARCHAR(120), expertise VARCHAR(160), status ENUM('ACTIVE','INACTIVE','PENDING','REJECTED') DEFAULT 'PENDING', attendance DECIMAL(5,2) DEFAULT 0, performance DECIMAL(5,2) DEFAULT 0, last_login_at DATETIME NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE students (id CHAR(36) PRIMARY KEY, name VARCHAR(120) NOT NULL, email VARCHAR(160) NOT NULL UNIQUE, department VARCHAR(120), mentor_id CHAR(36) NULL, internship_status VARCHAR(40), progress DECIMAL(5,2) DEFAULT 0, attendance DECIMAL(5,2) DEFAULT 0, performance DECIMAL(5,2) DEFAULT 0, CONSTRAINT fk_student_mentor FOREIGN KEY (mentor_id) REFERENCES mentors(id) ON DELETE SET NULL);
CREATE TABLE notifications (id CHAR(36) PRIMARY KEY, title VARCHAR(180) NOT NULL, message TEXT NOT NULL, audience VARCHAR(40) NOT NULL, status ENUM('DRAFT','SCHEDULED','PUBLISHED') DEFAULT 'DRAFT', scheduled_at DATETIME NULL, created_by CHAR(36), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (created_by) REFERENCES admins(id));
CREATE TABLE audit_logs (id CHAR(36) PRIMARY KEY, actor_id CHAR(36) NULL, actor_name VARCHAR(120) NOT NULL, actor_type ENUM('ADMIN','MENTOR','SYSTEM') NOT NULL, action VARCHAR(180) NOT NULL, details TEXT, ip_address VARCHAR(45), status VARCHAR(30), created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE admin_settings (admin_id CHAR(36) PRIMARY KEY, theme ENUM('light','dark','system') DEFAULT 'light', email_notifications BOOLEAN DEFAULT TRUE, login_alerts BOOLEAN DEFAULT TRUE, weekly_summary BOOLEAN DEFAULT TRUE, two_factor_auth BOOLEAN DEFAULT FALSE, FOREIGN KEY (admin_id) REFERENCES admins(id) ON DELETE CASCADE);
